// Goal: discharge
//   (P1 && P2) ==> det_send_equal(r1, r2, post1_self_, post2_self_)
// where det_send_equal demands:
//   (a) (r1 is Ok) == (r2 is Ok)
//   (b) r1 is Ok ==> r1->Ok_0 == r2->Ok_0                (trivial: unit)
//   (c) post1_self_.view() == post2_self_.view()
//
// The trigger gap is on the two history-extension ensures: each contains a
// fresh `seq![LIoOp::Send{ ... post*_self_.my_end_point() ... }]` literal,
// so z3 never aligns the two seq-add patterns even though both `src`s equal
// `pre_self_.my_end_point()`. The repair is to name both events, witness
// they coincide, and finish with Seq extensionality.

let ev1: NetEvent = LIoOp::Send {
    s: LPacket { dst: recipient@, src: post1_self_.my_end_point(), msg: message@ }
};
let ev2: NetEvent = LIoOp::Send {
    s: LPacket { dst: recipient@, src: post2_self_.my_end_point(), msg: message@ }
};

// Pull every conjunct of the antecedent into the proof context. Then split
// on (r1 is Ok, r2 is Ok); under each branch all per-run ensures are usable
// as concrete equalities and the trigger gap closes.
if (post1_self_.my_end_point() == pre_self_.my_end_point())
    && (post1_self_.state() is Error <==> r1 is Err)
    && (r1 is Ok ==> post1_self_.state() is Sending)
    && (r1 is Ok ==> post1_self_.history() == pre_self_.history() + seq![ev1])
    && (post2_self_.my_end_point() == pre_self_.my_end_point())
    && (post2_self_.state() is Error <==> r2 is Err)
    && (r2 is Ok ==> post2_self_.state() is Sending)
    && (r2 is Ok ==> post2_self_.history() == pre_self_.history() + seq![ev2])
{
    // Bridge the my_end_point() trigger and the Send-event trigger.
    assert(post1_self_.my_end_point() == post2_self_.my_end_point());
    assert(ev1 == ev2);
    assert(seq![ev1] =~= seq![ev2]);
    assert(pre_self_.history() + seq![ev1] =~= pre_self_.history() + seq![ev2]);
    assert(pre_self_.history() + seq![ev1] == pre_self_.history() + seq![ev2]);

    // (Ok, Ok): histories agree via Seq extensionality.
    if (r1 is Ok) && (r2 is Ok) {
        assert(post1_self_.history() == pre_self_.history() + seq![ev1]);
        assert(post2_self_.history() == pre_self_.history() + seq![ev2]);
        assert(post1_self_.history() =~= post2_self_.history());
        assert(post1_self_.history() == post2_self_.history());
    }

    // (Err, Err): no per-run history ensures fire; histories are
    // unconstrained between the two runs in this branch, so we cannot
    // derive history equality from the given ensures.
}
